Add-Type -AssemblyName System.Drawing; $img = [System.Drawing.Image]::FromFile("image\Grow.png"); $bmp = new-object System.Drawing.Bitmap($img); $h = $bmp.Height; $top = -1; $bottom = -1; for ($y = 0; $y -lt $h; $y++) { $p = $bmp.GetPixel(0, $y); if ([math]::abs($p.R - 1) -lt 15 -and [math]::abs($p.G - 17) -lt 15 -and [math]::abs($p.B - 40) -lt 15) { if ($top -eq -1) { $top = $y }; $bottom = $y } }; Write-Host ($top / $h * 100) (($h - $bottom) / $h * 100)
